// Verify Meta webhook signature (HMAC-SHA256)
const crypto = require('crypto');
const secret = $env.WHATSAPP_APP_SECRET;
const signature = $input.first().headers['x-hub-signature-256'];
const body = JSON.stringify($input.first().body);
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(body).digest('hex');

if (signature !== expected) {
  throw new Error('Invalid webhook signature - possible forgery');
}

// Extract message details
const entry = $input.first().body.entry?.[0];
const change = entry?.changes?.[0]?.value;
const messages = change?.messages || [];

if (messages.length === 0) {
  return [{ json: { type: 'no_message' } }];
}

const msg = messages[0];
const phone = msg.from;
const messageId = msg.id;
const timestamp = msg.timestamp;

let text = '';
let messageType = msg.type;

if (msg.type === 'text') {
  text = msg.text?.body || '';
} else if (msg.type === 'interactive') {
  // Handle quick reply buttons
  const reply = msg.interactive;
  if (reply.type === 'button_reply') {
    text = reply.button_reply?.id || reply.button_reply?.title || '';
    messageType = 'button_reply';
  } else if (reply.type === 'list_reply') {
    text = reply.list_reply?.id || '';
    messageType = 'list_reply';
  }
} else if (msg.type === 'audio') {
  // Mark as needs-transcription; n8n pro can handle this via OpenAI Whisper
  text = '[voice message]';
}

return [{
  json: {
    phone,
    messageId,
    timestamp,
    text,
    messageType,
    tenantId: $env.TENANT_ID || 'default',
    businessPhoneId: change?.metadata?.phone_number_id
  }
}];

const session = $input.first().json;
const message = $('Parse & Verify Message').first().json;

// Merge session with incoming message
const context = session.value ? JSON.parse(session.value) : {
  state: 'greeting',
  messages: [],
  collectedData: {},
  language: 'en',
  lastActivity: null
};

// Append new message to context window (keep last 20 messages)
context.messages.push({
  role: 'user',
  content: message.text,
  timestamp: message.timestamp
});
if (context.messages.length > 20) {
  context.messages = context.messages.slice(-20);
}

context.phone = message.phone;
context.tenantId = message.tenantId;
context.lastActivity = new Date().toISOString();

return [{ json: { context, message } }];
